package com.example.sharehandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class ShareActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share)

        handleIntent(intent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleIntent(intent)
    }

    private fun handleIntent(intent: Intent) {
        when (intent.action) {
            Intent.ACTION_SEND -> handleSend(intent)
            Intent.ACTION_SEND_MULTIPLE -> handleSendMultiple(intent)
        }
    }

    private fun handleSend(intent: Intent) {
        when (intent.type) {
            "text/plain" -> {
                val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                sharedText?.let {
                    processSharedText(it)
                }
            }
            in listOf("image/png", "image/jpg", "image/jpeg") -> {
                val imageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
                imageUri?.let {
                    processSharedImage(it)
                }
            }
        }
    }

    private fun handleSendMultiple(intent: Intent) {
        if (intent.type?.startsWith("image/") == true) {
            val imageUris = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
            imageUris?.let {
                processSharedImages(it)
            }
        }
    }

    private fun processSharedText(text: String) {
        Toast.makeText(this, "Shared Text: $text", Toast.LENGTH_LONG).show()
    }

    private fun processSharedImage(imageUri: Uri) {
        Toast.makeText(this, "Shared Image: $imageUri", Toast.LENGTH_LONG).show()
    }

    private fun processSharedImages(imageUris: List<Uri>) {
        val message = "Shared Images: ${imageUris.joinToString()}"
        Toast.makeText(this, message, Toast.LENGTH_LONG).show()
    }
}